const items = $input.all();
return items.map(item => ({
  json: {
    id: item.json.id,
    url: item.json.url,
    Name: item.json.name,
    Slug: item.json.property_slug,
    Weight: item.json.property_weight,
    Tasks_To_Open: item.json.property_tasks_to_open,
    Jira_Epic_Key: item.json.property_jira_epic_key,
    // 前置 phase 依賴檢查用欄位｜實際輸出鍵名須在 n8n 執行一次後於本節點輸出確認
    HasPrevPhase: Array.isArray(item.json['property_前置phase']) && item.json['property_前置phase'].length > 0,
    PrevJiraEpicKey: item.json['property_前置jira_epic_key'],
  }
}));

const item = $('T02 Parse Notion Fields').first().json;
const raw = item.Tasks_To_Open ?? '';
const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length > 0);

const roleToFile = { Backend: 'tasks-backend.md', DevOps: 'tasks-devops.md', QA: 'tasks-qa.md', Frontend: 'tasks-frontend.md' };

const valid = [];
const invalid = [];

for (const line of lines) {
  const m = line.match(/^\[(Backend|DevOps|QA|Frontend)\]\[(AI|手動)\]\s*(.+?)｜TDD:\s*(.+?)(?:｜依賴:\s*(.+))?$/);
  if (!m) {
    invalid.push({ line, reason: '格式不符，需為 [角色][AI/手動] 標題｜TDD: 命名（可選｜依賴: T0X）' });
    continue;
  }
  const [, role, execMode, title, tdd, deps] = m;
  valid.push({
    line,
    role,
    execMode,
    title: title.trim(),
    tdd: tdd.trim(),
    dependsOn: deps ? deps.trim() : '',
    targetFile: roleToFile[role],
  });
}

return [{ json: { slug: item.Slug, notionPageId: item.id, notionPageUrl: item.url, valid, invalid } }];

const parsed = $('T04a Parse And Validate Inbox Lines').first().json;
const fileContents = {
  'tasks-backend.md': $('T04b1 Read tasks-backend.md (inbox)').first().json.content ?? '',
  'tasks-devops.md': $('T04b2 Read tasks-devops.md (inbox)').first().json.content ?? '',
  'tasks-qa.md': $('T04b3 Read tasks-qa.md (inbox)').first().json.content ?? '',
};

function maxTaskId(content) {
  const matches = [...content.matchAll(/### T(\d+) —/g)];
  if (matches.length === 0) return 0;
  return Math.max(...matches.map(m => parseInt(m[1], 10)));
}

const nextNum = {};
for (const f of Object.keys(fileContents)) nextNum[f] = maxTaskId(fileContents[f]) + 1;

const appended = {};
const results = [];

for (const task of parsed.valid) {
  const file = task.targetFile;
  const num = nextNum[file]++;
  const taskId = 'T' + String(num).padStart(2, '0');
  const depBlock = task.dependsOn ? `\n\n**依賴**：${task.dependsOn}` : '';
  const execLabel = task.execMode === 'AI' ? '🤖 AI 執行' : '👤 手動執行';
  const block = `\n\n### ${taskId} — ${task.title} ⬜　${execLabel}${depBlock}\n\n> 由 Notion 新增，詳細任務描述待補充\n\n**完成定義**：\n- 測試命名：\`${task.tdd}\`\n`;
  appended[file] = (appended[file] ?? '') + block;
  results.push({ file, taskId, title: task.title });
}

const basePath = 'D:/06_Workspace/Workspace_GitHub/xu3clayu83ire/alag-addyosmani-demos/awtw-short-url-service-agent/_spec/' + parsed.slug + '/';
const fileUpdates = Object.keys(appended).map(file => ({
  json: {
    file,
    filePath: basePath + file,
    newContent: (fileContents[file] ?? '').replace(/\s*$/, '') + appended[file] + '\n',
  }
}));

return fileUpdates;

const items = $input.all();
const files = items.map(i => i.json.filePath).filter(Boolean);
return [{ json: { files, hasFiles: files.length > 0 } }];

const parsed = $('T04a Parse And Validate Inbox Lines').first().json;
const lines = parsed.invalid.map(x => `- ${x.line}\n  原因：${x.reason}`).join('\n');
const content = `⚠️ Tasks_To_Open 有 ${parsed.invalid.length} 行格式錯誤，請修正後重新填入：\n${lines}`;
return [{ json: { notionPageId: parsed.notionPageId, commentContent: content } }];

const parsed = $('T04a Parse And Validate Inbox Lines').first().json;
const newValue = parsed.invalid.map(x => x.line).join('\n');
return [{ json: { notionPageId: parsed.notionPageId, newTasksToOpen: newValue } }];

const files = {
  'tasks-backend.md': { content: $('T06 Read Tasks Backend').first().json.content ?? '', role: 'Backend' },
  'tasks-devops.md': { content: $('T06b Read Tasks DevOps').first().json.content ?? '', role: 'DevOps' },
  'tasks-qa.md': { content: $('T06c Read Tasks QA').first().json.content ?? '', role: 'QA' },
};

const phase = $('T02 Parse Notion Fields').first().json;

function splitBlocks(content) {
  if (!content) return [];
  const blocks = content.split(/(?=^### T\d+ )/m).filter(b => b.trim().startsWith('### T'));
  return blocks.map(block => {
    const headerMatch = block.match(/^### (T\d+) — (.+?) ([⬜✅])\s*(?:　(.+?))?\s*(?:\((ASUS-\d+(?:,\s*ASUS-\d+)*)\))?\s*$/m);
    if (!headerMatch) return null;
    const [, taskId, title, statusIcon, execMode, existingJiraKeys] = headerMatch;
    const depMatch = block.match(/\*\*依賴\*\*[：:]\s*(T\d+(?:[,、]\s*T\d+)*)/);
    const tddMatch = block.match(/測試命名[：:]\s*`([^`]+)`/);
    return {
      taskId,
      title: title.trim(),
      status: statusIcon === '✅' ? 'done' : 'todo',
      alreadyTicketed: Boolean(existingJiraKeys),
      execMode: execMode ? execMode.trim() : '',
      dependsOn: depMatch ? depMatch[1].split(/[,、]\s*/) : [],
      tdd: tddMatch ? tddMatch[1].trim() : '',
      body: block.trim(),
    };
  }).filter(Boolean);
}

const statusMap = {};
const allBlocksByFile = {};
for (const [file, info] of Object.entries(files)) {
  const blocks = splitBlocks(info.content);
  allBlocksByFile[file] = blocks;
  for (const b of blocks) {
    statusMap[b.taskId] = b.status === 'done' ? 'done' : (b.alreadyTicketed ? 'ticketed' : 'todo');
  }
}

const eligible = [];
for (const [file, info] of Object.entries(files)) {
  for (const b of allBlocksByFile[file]) {
    if (b.status !== 'todo' || b.alreadyTicketed) continue;
    const blocked = b.dependsOn.some(dep => statusMap[dep] !== 'done');
    if (blocked) continue;
    eligible.push({
      json: {
        slug: phase.Slug,
        notionPageId: phase.id,
        notionPageUrl: phase.url,
taskId: b.taskId,
        title: b.title,
        tdd: b.tdd,
        body: b.body,
        execMode: b.execMode.includes('手動') ? '手動' : 'AI',
        role: info.role,
        sourceFile: file,
      }
    });
  }
}

return eligible;

