const jiraResults = $input.all();
const originals = $('T07 Split Tasks And Dependency Guard').all();

const perTask = jiraResults.map((r, idx) => ({
  jiraKey: r.json.key,
  taskId: originals[idx] ? originals[idx].json.taskId : undefined,
  sourceFile: originals[idx] ? originals[idx].json.sourceFile : undefined,
  slug: originals[idx] ? originals[idx].json.slug : undefined,
}));

const allKeys = perTask.map(p => p.jiraKey).filter(Boolean);

return [{ json: { perTask, allKeys, slug: originals[0] ? originals[0].json.slug : '', notionPageId: originals[0] ? originals[0].json.notionPageId : '' } }];

const data = $input.first().json;
const perTask = data.perTask;

const byFile = {};
for (const t of perTask) {
  if (!t.sourceFile) continue;
  byFile[t.sourceFile] = byFile[t.sourceFile] || [];
  byFile[t.sourceFile].push(t);
}

const fileContents = {
  'tasks-backend.md': $('T06 Read Tasks Backend').first().json.content ?? '',
  'tasks-devops.md': $('T06b Read Tasks DevOps').first().json.content ?? '',
  'tasks-qa.md': $('T06c Read Tasks QA').first().json.content ?? '',
};

const updates = [];
for (const [file, tasks] of Object.entries(byFile)) {
  let content = fileContents[file] ?? '';
  for (const t of tasks) {
    const re = new RegExp('(### ' + t.taskId + ' — .+?)⬜(.*)$', 'm');
    if (!re.test(content)) continue;
    content = content.replace(re, (m, before, after) => before + '⬜' + after + `　(${t.jiraKey})`);
  }
  updates.push({
    file,
    filePath: 'D:/06_Workspace/Workspace_GitHub/xu3clayu83ire/alag-addyosmani-demos/awtw-short-url-service-agent/_spec/' + data.slug + '/' + file,
    content,
  });
}

return updates.map(u => ({ json: u }));

const items = $input.all();
const files = items.map(i => i.json.filePath).filter(Boolean);
return [{ json: { files, hasFiles: files.length > 0 } }];

const page = $json;
// Notion 單頁 get 操作的簡化輸出格式跟批次 getAll 不一定一致，防禦性嘗試多種可能欄位路徑
function extractExistingJiraKey(p) {
  if (typeof p.property_jira_epic_key === 'string' && p.property_jira_epic_key) return p.property_jira_epic_key;
  if (typeof p.Jira_Epic_Key === 'string' && p.Jira_Epic_Key) return p.Jira_Epic_Key;
  const rt = p.properties?.Jira_Epic_Key?.rich_text;
  if (Array.isArray(rt)) return rt.map(t => t.plain_text).join('');
  return '';
}

const existingRaw = extractExistingJiraKey(page);
const pairData = $('T14 Pair Jira Keys With Tasks').first().json;
const newKeys = pairData.allKeys ?? [];

const merged = [existingRaw, ...newKeys]
  .filter(Boolean)
  .flatMap(s => String(s).split(',').map(k => k.trim()))
  .filter(Boolean)
  .filter((k, i, arr) => arr.indexOf(k) === i)
  .join(', ');

return [{ json: { notionPageId: pairData.notionPageId, allKeys: merged, _debug_existingRaw: existingRaw } }];

const phase = $('T02 Parse Notion Fields').first().json;
const specContent = $('T09 Read Spec.md').first().json.content ?? '（尚無 spec.md）';
const designContent = $('T10 Read Design.md').first().json.content ?? '（尚無 design.md）';
const backendTasks = $('T06 Read Tasks Backend').first().json.content ?? '';
const devopsTasks = $('T06b Read Tasks DevOps').first().json.content ?? '';
const qaTasks = $('T06c Read Tasks QA').first().json.content ?? '';

const title = phase.Name ?? phase.Slug;
const weight = phase.Weight ?? 99;

const frontMatter = (docTitle) => `---
title: "${docTitle}"
weight: ${weight}
---

`;

const indexContent = frontMatter(title) +
  `## ${title}\n\n` +
  `- [規格文件](spec.md)\n` +
  `- [設計文件](design.md)\n` +
  `- [任務清單](tasks.md)\n`;

const specDoc = frontMatter(title + ' — 規格文件') + specContent;
const designDoc = frontMatter(title + ' — 設計文件') + designContent;
const tasksDoc = frontMatter(title + ' — 任務清單') +
  `## Backend\n\n${backendTasks}\n\n## DevOps\n\n${devopsTasks}\n\n## QA\n\n${qaTasks}\n`;

const basePath = 'D:/06_Workspace/Workspace_GitHub/xu3clayu83ire/alag-addyosmani-demos/awtw-short-url-service-agent/hugo-docs/content/docs/' + phase.Slug + '/';

return [
  { json: { filePath: basePath + '_index.md', content: indexContent } },
  { json: { filePath: basePath + 'spec.md', content: specDoc } },
  { json: { filePath: basePath + 'design.md', content: designDoc } },
  { json: { filePath: basePath + 'tasks.md', content: tasksDoc } },
];
